int lo = 0, hi = nums.length - 1;
while (lo <= hi) {
    int mid = (lo + hi) / 2;
    if (nums[mid] == target) {
        System.out.println("Found at " + mid);
        break;
    } else if (nums[mid] < target) {
        lo = mid + 1;
    } else {
        hi = mid - 1;
